"""Core module for the MsgQueue framework."""
import time
import uuid


class QueueError(Exception):
    """Base exception for all messaging queue operations."""

    def __init__(self, message, code=None, retryable=False):
        super().__init__(message)
        self.code = code
        self.retryable = retryable
        self.timestamp = time.time()

    def __repr__(self):
        return f"QueueError({self.args[0]!r}, code={self.code})"

    def to_dict(self):
        return {"message": str(self), "code": self.code, "retryable": self.retryable}


class TopicError(QueueError):
    """Raised when a topic is invalid."""
    pass


def create_queue(name, config=None, strict=False, capacity=1000):
    """Create and return a new MessageBroker instance."""
    if config is None:
        config = {}
    if strict and not isinstance(config, dict):
        raise QueueError("Config must be a dict", code="INVALID_CONFIG")
    broker_id = str(uuid.uuid4())[:8]
    return MessageBroker(broker_id=broker_id, name=name, config=config, capacity=capacity)


class MessageBroker:
    """Main message broker instance."""

    def __init__(self, broker_id, name, config, capacity):
        self.broker_id = broker_id
        self.name = name
        self.config = config
        self.capacity = capacity
        self._messages = {}
        self._running = False

    def start(self):
        if self._running:
            raise QueueError("Broker already running")
        self._running = True

    def stop(self):
        if not self._running:
            raise QueueError("Broker not running")
        self._running = False

    def publish(self, topic, payload):
        if not self._running:
            raise QueueError("Cannot publish: broker not running")
        msg_id = str(uuid.uuid4())[:8]
        self._messages[msg_id] = {"topic": topic, "payload": payload, "ts": time.time()}
        return msg_id

    def consume(self, msg_id):
        if msg_id not in self._messages:
            raise QueueError(f"Message not found: {msg_id}", code="NOT_FOUND")
        return self._messages.pop(msg_id)

