"""Message producer for publishing to queues."""
from msgqueue.core import QueueError, create_queue


class Producer:
    """Publishes messages to a broker."""

    def __init__(self, name, config=None):
        self.name = name
        self._broker = create_queue(f"producer-{name}", config)
        self._sent = 0

    def connect(self):
        try:
            self._broker.start()
        except QueueError:
            raise QueueError(f"Producer '{self.name}' already connected")

    def send(self, topic, payload):
        try:
            msg_id = self._broker.publish(topic, payload)
            self._sent += 1
            return msg_id
        except QueueError:
            raise QueueError(f"Producer '{self.name}' failed to send")

    def disconnect(self):
        try:
            self._broker.stop()
        except QueueError:
            raise QueueError(f"Producer '{self.name}' not connected")


class BatchProducer(Producer):
    """Sends messages in batches."""

    def __init__(self, name, batch_size=10):
        super().__init__(name)
        self._batch_size = batch_size
        self._buffer = []
        self._batch_broker = create_queue(f"batch-{name}", {"batch": True})

    def buffer_message(self, topic, payload):
        if len(self._buffer) >= self._batch_size:
            raise QueueError(f"Batch buffer full ({self._batch_size})")
        self._buffer.append({"topic": topic, "payload": payload})

    def flush(self):
        if not self._buffer:
            raise QueueError("Nothing to flush: buffer empty")
        sent = []
        for msg in self._buffer:
            sent.append(self.send(msg["topic"], msg["payload"]))
        self._buffer.clear()
        return sent

