"""Message consumer for reading from queues."""
from msgqueue.core import QueueError, create_queue


class Consumer:
    """Consumes messages from a broker."""

    def __init__(self, name, group=None):
        self.name = name
        self.group = group
        self._broker = create_queue(f"consumer-{name}", {"group": group})
        self._received = 0

    def connect(self):
        try:
            self._broker.start()
        except QueueError:
            raise QueueError(f"Consumer '{self.name}' already connected")

    def receive(self, msg_id):
        try:
            msg = self._broker.consume(msg_id)
            self._received += 1
            return msg
        except QueueError:
            raise QueueError(f"Consumer '{self.name}' failed to receive {msg_id}")

    def disconnect(self):
        try:
            self._broker.stop()
        except QueueError:
            raise QueueError(f"Consumer '{self.name}' not connected")


class ConsumerGroup:
    """Manages a group of consumers."""

    def __init__(self, group_name, size=3):
        if size <= 0:
            raise QueueError("Consumer group size must be positive")
        self.group_name = group_name
        self._consumers = []
        for i in range(size):
            self._consumers.append(Consumer(f"{group_name}-{i}", group=group_name))
        self._coordinator = create_queue(f"group-{group_name}", {"size": size})

    def connect_all(self):
        for c in self._consumers:
            c.connect()

    def rebalance(self, new_size):
        if new_size <= 0:
            raise QueueError("Cannot rebalance to zero consumers")
        for i in range(len(self._consumers), new_size):
            self._consumers.append(Consumer(f"{self.group_name}-{i}", group=self.group_name))

