"""Message routing for topic-based delivery."""
import hashlib
from msgqueue.core import QueueError, create_queue


class Route:
    """A single topic route."""

    def __init__(self, pattern, handler):
        self.pattern = pattern
        self.handler = handler

    def matches(self, topic):
        return topic.startswith(self.pattern)

    def dispatch(self, message):
        try:
            return self.handler(message)
        except Exception as e:
            raise QueueError(f"Route '{self.pattern}' dispatch failed: {e}")


class Router:
    """Routes messages to handlers by topic."""

    def __init__(self):
        self._routes = []
        self._dead_letter = create_queue("dead-letter", {"max_size": 500})

    def add_route(self, pattern, handler):
        if not callable(handler):
            raise QueueError(f"Handler for '{pattern}' must be callable")
        self._routes.append(Route(pattern, handler))

    def route(self, topic, message):
        for r in self._routes:
            if r.matches(topic):
                return r.dispatch(message)
        raise QueueError(f"No route for topic '{topic}'", code="NO_ROUTE")

    def remove_route(self, pattern):
        before = len(self._routes)
        self._routes = [r for r in self._routes if r.pattern != pattern]
        if len(self._routes) == before:
            raise QueueError(f"Route '{pattern}' not found")


class TopicRouter(Router):
    """Hash-based topic routing with partitions."""

    def __init__(self, num_partitions=4):
        super().__init__()
        if num_partitions <= 0:
            raise QueueError("num_partitions must be positive")
        self._partitions = {}
        for i in range(num_partitions):
            self._partitions[i] = create_queue(f"topic-part-{i}", {"partition": i})

    def get_partition(self, topic):
        h = int(hashlib.md5(topic.encode()).hexdigest(), 16)
        idx = h % len(self._partitions)
        if idx not in self._partitions:
            raise QueueError(f"Partition {idx} not found", code="ROUTING")
        return self._partitions[idx]

