"""Retry logic for failed message deliveries."""
import time
from msgqueue.core import QueueError, create_queue


class RetryPolicy:
    """Retries operations that raise QueueError."""

    def __init__(self, max_retries=3, backoff=0.01):
        self.max_retries = max_retries
        self.backoff = backoff
        self._history = []

    def execute_with_retry(self, func, *args, **kwargs):
        last_error = None
        for attempt in range(self.max_retries + 1):
            try:
                return func(*args, **kwargs)
            except QueueError as e:
                last_error = e
                self._history.append({"attempt": attempt, "error": str(e)})
                time.sleep(self.backoff)
        raise QueueError(f"All {self.max_retries + 1} attempts failed: {last_error}")

    def get_history(self):
        return list(self._history)


class DeadLetterHandler:
    """Handles messages that failed all retries."""

    def __init__(self, name="dead-letter"):
        self._store = create_queue(name, {"type": "dead-letter"})
        self._failed = []

    def record_failure(self, message, error):
        if not isinstance(error, QueueError):
            raise TypeError(f"Expected QueueError, got {type(error).__name__}")
        self._failed.append({"message": message, "error": str(error)})

    def get_failures(self):
        return list(self._failed)

    def retry_all(self, handler):
        if not self._failed:
            raise QueueError("No failed messages to retry")
        results = []
        for entry in self._failed:
            try:
                results.append(handler(entry["message"]))
            except QueueError:
                raise QueueError(f"Retry failed for: {entry['message']}")
        self._failed.clear()
        return results

