"""Middleware pipeline for message processing."""
from msgqueue.core import QueueError, create_queue


class Middleware:
    """Base middleware class."""

    def __init__(self, name):
        self.name = name

    def process(self, message, next_fn):
        return next_fn(message)


class LoggingMiddleware(Middleware):
    """Logs message processing and catches QueueError."""

    def __init__(self):
        super().__init__("logging")
        self.log = []

    def process(self, message, next_fn):
        self.log.append({"message": message, "event": "enter"})
        try:
            result = next_fn(message)
            self.log.append({"message": message, "event": "exit"})
            return result
        except QueueError as e:
            self.log.append({"message": message, "event": "error", "detail": str(e)})
            raise


class ValidationMiddleware(Middleware):
    """Validates messages before processing."""

    def __init__(self, required_fields=None):
        super().__init__("validation")
        self._required = required_fields or ["topic", "payload"]

    def process(self, message, next_fn):
        for field in self._required:
            if field not in message:
                raise QueueError(f"Missing required field: '{field}'")
        return next_fn(message)


class MiddlewarePipeline:
    """Chains middleware for sequential processing."""

    def __init__(self):
        self._middleware = []
        self._context = create_queue("pipeline", {"type": "middleware"})

    def add(self, mw):
        if not isinstance(mw, Middleware):
            raise QueueError(f"Expected Middleware, got {type(mw).__name__}")
        self._middleware.append(mw)

    def execute(self, message, handler):
        if not self._middleware:
            raise QueueError("No middleware configured")
        def build(i):
            if i >= len(self._middleware):
                return handler
            return lambda m: self._middleware[i].process(m, build(i + 1))
        return build(0)(message)

    def clear(self):
        self._middleware.clear()
        self._context = create_queue("pipeline-reset", {"type": "middleware"})

