"""Monitoring and health checks for the messaging system."""
from msgqueue.core import QueueError, create_queue


class Monitor:
    """Tracks QueueError occurrences and system health."""

    def __init__(self):
        self._errors = []
        self._checks = {}
        self._store = create_queue("monitor", {"type": "health"})

    def record_error(self, error):
        if not isinstance(error, QueueError):
            raise TypeError(f"Expected QueueError, got {type(error).__name__}")
        self._errors.append({"message": str(error), "code": error.code})

    def get_error_count(self):
        return len(self._errors)

    def register_check(self, name, check_fn):
        self._checks[name] = check_fn

    def run_checks(self):
        results = {}
        for name, fn in self._checks.items():
            try:
                fn()
                results[name] = "healthy"
            except QueueError as e:
                self.record_error(e)
                results[name] = f"unhealthy: {e}"
        return results


class AlertManager:
    """Manages alerts based on error thresholds."""

    def __init__(self, threshold=10):
        self._threshold = threshold
        self._alerts = []
        self._alert_queue = create_queue("alerts", {"threshold": threshold})

    def check_threshold(self, monitor):
        count = monitor.get_error_count()
        if count >= self._threshold:
            raise QueueError(f"Error threshold exceeded: {count} >= {self._threshold}")
        return count

    def add_alert(self, message):
        self._alerts.append(message)

    def get_alerts(self):
        if not self._alerts:
            raise QueueError("No alerts recorded")
        return list(self._alerts)

