"""Serialization utilities for message data."""
import json
from msgqueue.core import QueueError, create_queue


def serialize_message(topic, payload):
    """Serialize a message to JSON string."""
    try:
        return json.dumps({"topic": topic, "payload": payload})
    except (TypeError, ValueError) as e:
        raise QueueError(f"Cannot serialize message: {e}", code="SERIALIZE")


def deserialize_message(data):
    """Deserialize a JSON string to message."""
    try:
        parsed = json.loads(data)
        return parsed["topic"], parsed["payload"]
    except (json.JSONDecodeError, KeyError) as e:
        raise QueueError(f"Cannot deserialize message: {e}", code="DESERIALIZE")


def serialize_error(error):
    if not isinstance(error, QueueError):
        raise TypeError(f"Expected QueueError, got {type(error).__name__}")
    return error.to_dict()


def deserialize_error(data):
    return QueueError(message=data.get("message", ""), code=data.get("code"))


def validate_and_create(name, config_json, strict=True):
    try:
        config = json.loads(config_json)
    except json.JSONDecodeError as e:
        raise QueueError(f"Invalid config JSON: {e}")
    return create_queue(name=name, config=config, strict=strict)


def batch_deserialize_errors(data_list):
    errors = []
    for data in data_list:
        try:
            errors.append(QueueError(message=data["message"], code=data.get("code")))
        except (KeyError, TypeError) as e:
            raise QueueError(f"Invalid error data: {e}")
    return errors
